 * 4. Visit /susanboyle/ to see the populated template
 */

(function() {
    'use strict';

    const BizBioEngine = {
        config: {
            dataFile: 'data.json',
            templatesPath: '../templates/',
            vcardGeneratorPath: '../vcard-generator.js',
