import { fileURLToPath } from "node:url";
import { defineNuxtConfig } from "nuxt/config";

// https://nuxt.com/docs/api/configuration/nuxt-config
export default defineNuxtConfig({
  compatibilityDate: '2025-11-23',
  devtools: {
    enabled: false,
  },
  ssr: true,
  modules: [
    '@nuxtjs/tailwindcss',
