        proxy_cache_bypass $http_upgrade;

        # Cache static assets
        expires 7d;
        add_header Cache-Control "public";
    }

    # Known Nuxt frontend routes - proxy to Node.js
    location ~ ^/(login|register|dashboard|profile|settings|admin|logout|about|contact|pricing|features|organizations|catalogs|search|help|verify-email|verify-sent|terms|privacy|categories)(/.*)?$ {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;
    }

    # ==========================================
    # API ROUTES (proxied to ASP.NET backend)
    # ==========================================

    location ^~ /api/ {
        proxy_pass http://127.0.0.1:5000;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_read_timeout 60s;
        proxy_connect_timeout 60s;
    }

    # ==========================================
    # HOME PAGE
    # ==========================================

    # Root path - serve Nuxt home page
    location = / {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;
    }

    # ==========================================
    # PROFILE SLUGS (static HTML from disk)
    # ==========================================

    # Everything else is a profile slug - serve from persistent profiles directory
    location / {
        root /var/www/snaptap/ui/profiles;
        try_files $uri/index.html $uri.html @nuxt_fallback;

        # Allow CORS for profile assets
        add_header Access-Control-Allow-Origin "*" always;
    }

    # Fallback to Nuxt for dynamic routes or 404 handling
    location @nuxt_fallback {
        proxy_pass http://127.0.0.1:3001;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;
    }
}

# ==========================================
# HTTP to HTTPS redirect
# ==========================================

server {
    listen 80;
    server_name snaptap.co.za www.snaptap.co.za;
    return 301 https://snaptap.co.za$request_uri;
}

